var points = 0;

function game(iteration){

    var pointP = document.getElementById('points');
    var gDiv = document.getElementById('gameFrame');

    pointP.innerHTML = "points " + points;
    gDiv.innerHTML = "";

    var cs = 0;

    function check(side){

        if(side == cs){
            points += 1;
        } else {
            points = 0;
        }
        game(0);
    }

    function createButtons(a, b) {
        var btn1 = document.createElement("button");
        var btn2 = document.createElement("button");

        btn1.innerHTML = a;
        btn1.onclick = function() { check(0); };

        btn2.innerHTML = b;
        btn2.onclick = function() { check(1); };

        gDiv.appendChild(btn1);
        gDiv.appendChild(btn2);

    }

    const random1 = Math.floor(Math.random() * r.length);
    const random2 = Math.floor(Math.random() * b.length);

    if (Math.random() < 0.5){
        cs = 0;
        createButtons(r[random1], b[random2]);
    } else {
        cs = 1;
        createButtons(b[random2], r[random1]);
    }
}

function init(){

   points = 0;

   var gDiv = document.getElementById('gameFrame');
   var btn = document.createElement("button");

   btn.innerHTML = "start";
   btn.onclick = function() { game(0) };
   btn.id = "startb";

   gDiv.appendChild(btn);

}

window.onload = init
